using UnityEngine;
using UnityEngine.UI;
using UnityEditor;
using UnityEditor.SceneManagement;

public class VictoryPanelBuilder
{
    [MenuItem("Tools/Build Victory Panel")]
    public static void Build()
    {
        // Find Canvas
        var canvas = GameObject.FindObjectOfType<Canvas>();
        if (canvas == null)
        {
            Debug.LogError("Canvas not found!");
            return;
        }

        // Check if victory panel already exists
        var existing = canvas.transform.Find("胜利界面");
        if (existing != null)
        {
            Debug.Log("Victory panel already exists, skipping.");
            return;
        }

        // Color palette matching the game's cartoon style
        var panelBgColor = new Color(0.18f, 0.12f, 0.08f, 0.96f);      // Dark warm brown
        var overlayColor = new Color(0f, 0f, 0f, 0.65f);                 // Semi-transparent black
        var titleColor = new Color(1f, 0.85f, 0.1f);                     // Gold/yellow
        var starFilledColor = new Color(1f, 0.85f, 0f, 1f);              // Bright gold
        var starEmptyColor = new Color(0.35f, 0.3f, 0.25f, 0.6f);        // Dim grey-brown
        var labelColor = new Color(0.85f, 0.78f, 0.65f);                 // Light warm cream
        var valueColor = Color.white;                                       // White
        var btnGreenColor = new Color(0.2f, 0.72f, 0.35f, 1f);           // Bright green
        var btnOrangeColor = new Color(0.92f, 0.55f, 0.12f, 1f);         // Warm orange
        var btnTextColor = Color.white;
        var dividerColor = new Color(1f, 0.85f, 0.1f, 0.3f);             // Gold divider
        var ribbonColor = new Color(0.12f, 0.55f, 0.22f, 0.9f);          // Deep green ribbon

        // === ROOT: 胜利界面 (VictoryPanel) ===
        var rootObj = CreateUIObject("胜利界面", canvas.transform);
        var rootRect = rootObj.GetComponent<RectTransform>();
        SetFullStretch(rootRect);
        rootObj.SetActive(false);

        // === OVERLAY: 遮罩 ===
        var overlayObj = CreateUIObject("遮罩", rootObj.transform);
        var overlayRect = overlayObj.GetComponent<RectTransform>();
        SetFullStretch(overlayRect);
        var overlayImg = overlayObj.AddComponent<Image>();
        overlayImg.color = overlayColor;
        overlayImg.raycastTarget = true;

        // === PANEL: 面板背景 ===
        var panelObj = CreateUIObject("面板背景", rootObj.transform);
        var panelRect = panelObj.GetComponent<RectTransform>();
        panelRect.anchorMin = new Vector2(0.5f, 0.5f);
        panelRect.anchorMax = new Vector2(0.5f, 0.5f);
        panelRect.pivot = new Vector2(0.5f, 0.5f);
        panelRect.sizeDelta = new Vector2(600f, 720f);
        panelRect.anchoredPosition = Vector2.zero;
        var panelImg = panelObj.AddComponent<Image>();
        panelImg.color = panelBgColor;
        panelImg.raycastTarget = true;

        // === DECORATIVE TOP RIBBON ===
        var ribbonObj = CreateUIObject("装饰丝带", panelObj.transform);
        var ribbonRect = ribbonObj.GetComponent<RectTransform>();
        ribbonRect.anchorMin = new Vector2(0f, 1f);
        ribbonRect.anchorMax = new Vector2(1f, 1f);
        ribbonRect.pivot = new Vector2(0.5f, 1f);
        ribbonRect.sizeDelta = new Vector2(0f, 8f);
        ribbonRect.anchoredPosition = Vector2.zero;
        var ribbonImg = ribbonObj.AddComponent<Image>();
        ribbonImg.color = ribbonColor;

        // === TITLE: 胜利标题 ===
        var titleObj = CreateUIObject("胜利标题", panelObj.transform);
        var titleRect = titleObj.GetComponent<RectTransform>();
        titleRect.anchorMin = new Vector2(0f, 1f);
        titleRect.anchorMax = new Vector2(1f, 1f);
        titleRect.pivot = new Vector2(0.5f, 1f);
        titleRect.sizeDelta = new Vector2(0f, 100f);
        titleRect.anchoredPosition = new Vector2(0f, -30f);
        var titleText = titleObj.AddComponent<Text>();
        titleText.text = "胜 利 !";
        titleText.font = Resources.GetBuiltinResource<Font>("LegacyRuntime.ttf");
        titleText.fontSize = 56;
        titleText.fontStyle = FontStyle.Bold;
        titleText.color = titleColor;
        titleText.alignment = TextAnchor.MiddleCenter;
        titleText.raycastTarget = false;

        // === GOLD DIVIDER ===
        var dividerObj = CreateUIObject("分割线", panelObj.transform);
        var dividerRect = dividerObj.GetComponent<RectTransform>();
        dividerRect.anchorMin = new Vector2(0.1f, 1f);
        dividerRect.anchorMax = new Vector2(0.9f, 1f);
        dividerRect.pivot = new Vector2(0.5f, 1f);
        dividerRect.sizeDelta = new Vector2(0f, 3f);
        dividerRect.anchoredPosition = new Vector2(0f, -130f);
        var dividerImg = dividerObj.AddComponent<Image>();
        dividerImg.color = dividerColor;

        // === STARS AREA ===
        var starsObj = CreateUIObject("星星区域", panelObj.transform);
        var starsRect = starsObj.GetComponent<RectTransform>();
        starsRect.anchorMin = new Vector2(0f, 1f);
        starsRect.anchorMax = new Vector2(1f, 1f);
        starsRect.pivot = new Vector2(0.5f, 1f);
        starsRect.sizeDelta = new Vector2(0f, 120f);
        starsRect.anchoredPosition = new Vector2(0f, -145f);

        Image[] starImages = new Image[3];
        float[] starXPositions = { -80f, 0f, 80f };
        for (int i = 0; i < 3; i++)
        {
            var starObj = CreateUIObject($"Star{i + 1}", starsObj.transform);
            var starRect = starObj.GetComponent<RectTransform>();
            starRect.anchorMin = new Vector2(0.5f, 0.5f);
            starRect.anchorMax = new Vector2(0.5f, 0.5f);
            starRect.pivot = new Vector2(0.5f, 0.5f);
            starRect.sizeDelta = new Vector2(70f, 70f);
            starRect.anchoredPosition = new Vector2(starXPositions[i], 0f);
            var starImg = starObj.AddComponent<Image>();
            starImg.color = starFilledColor;
            starImg.raycastTarget = false;
            starImages[i] = starImg;
        }

        // === STATS AREA ===
        var statsObj = CreateUIObject("统计区域", panelObj.transform);
        var statsRect = statsObj.GetComponent<RectTransform>();
        statsRect.anchorMin = new Vector2(0f, 1f);
        statsRect.anchorMax = new Vector2(1f, 1f);
        statsRect.pivot = new Vector2(0.5f, 1f);
        statsRect.sizeDelta = new Vector2(0f, 200f);
        statsRect.anchoredPosition = new Vector2(0f, -275f);

        // Stats items
        string[] statLabels = { "击杀数", "剩余金币", "存活波次" };
        float[] statYPositions = { -20f, -75f, -130f };
        Text[] statValueTexts = new Text[3];

        for (int i = 0; i < 3; i++)
        {
            // Stat row
            var statRowObj = CreateUIObject($"StatRow{i}", statsObj.transform);
            var statRowRect = statRowObj.GetComponent<RectTransform>();
            statRowRect.anchorMin = new Vector2(0.1f, 1f);
            statRowRect.anchorMax = new Vector2(0.9f, 1f);
            statRowRect.pivot = new Vector2(0.5f, 1f);
            statRowRect.sizeDelta = new Vector2(0f, 45f);
            statRowRect.anchoredPosition = new Vector2(0f, statYPositions[i]);

            // Stat background
            var rowBg = statRowObj.AddComponent<Image>();
            rowBg.color = new Color(1f, 1f, 1f, 0.06f);
            rowBg.raycastTarget = false;

            // Stat label
            var labelObj = CreateUIObject("Label", statRowObj.transform);
            var labelRect = labelObj.GetComponent<RectTransform>();
            labelRect.anchorMin = new Vector2(0f, 0f);
            labelRect.anchorMax = new Vector2(0.45f, 1f);
            labelRect.sizeDelta = Vector2.zero;
            labelRect.offsetMin = new Vector2(20f, 0f);
            labelRect.offsetMax = new Vector2(0f, 0f);
            var labelText = labelObj.AddComponent<Text>();
            labelText.text = statLabels[i];
            labelText.font = Resources.GetBuiltinResource<Font>("LegacyRuntime.ttf");
            labelText.fontSize = 26;
            labelText.color = labelColor;
            labelText.alignment = TextAnchor.MiddleLeft;
            labelText.raycastTarget = false;

            // Stat value
            var valueObj = CreateUIObject("Value", statRowObj.transform);
            var valueRect = valueObj.GetComponent<RectTransform>();
            valueRect.anchorMin = new Vector2(0.55f, 0f);
            valueRect.anchorMax = new Vector2(1f, 1f);
            valueRect.sizeDelta = Vector2.zero;
            valueRect.offsetMin = new Vector2(0f, 0f);
            valueRect.offsetMax = new Vector2(-20f, 0f);
            var valueText = valueObj.AddComponent<Text>();
            valueText.text = "0";
            valueText.font = Resources.GetBuiltinResource<Font>("LegacyRuntime.ttf");
            valueText.fontSize = 28;
            valueText.fontStyle = FontStyle.Bold;
            valueText.color = valueColor;
            valueText.alignment = TextAnchor.MiddleRight;
            valueText.raycastTarget = false;
            statValueTexts[i] = valueText;
        }

        // === BUTTONS AREA ===
        var btnsObj = CreateUIObject("按钮区域", panelObj.transform);
        var btnsRect = btnsObj.GetComponent<RectTransform>();
        btnsRect.anchorMin = new Vector2(0f, 0f);
        btnsRect.anchorMax = new Vector2(1f, 0f);
        btnsRect.pivot = new Vector2(0.5f, 0f);
        btnsRect.sizeDelta = new Vector2(0f, 120f);
        btnsRect.anchoredPosition = new Vector2(0f, 40f);

        // Restart button
        var restartBtnObj = CreateUIObject("重新挑战按钮", btnsObj.transform);
        var restartRect = restartBtnObj.GetComponent<RectTransform>();
        restartRect.anchorMin = new Vector2(0.08f, 0.15f);
        restartRect.anchorMax = new Vector2(0.46f, 0.85f);
        restartRect.sizeDelta = Vector2.zero;
        var restartBtnImg = restartBtnObj.AddComponent<Image>();
        restartBtnImg.color = btnOrangeColor;
        restartBtnImg.raycastTarget = true;
        var restartBtn = restartBtnObj.AddComponent<Button>();
        restartBtn.targetGraphic = restartBtnImg;
        var restartBtnTextObj = CreateUIObject("Text", restartBtnObj.transform);
        var restartBtnTextRect = restartBtnTextObj.GetComponent<RectTransform>();
        SetFullStretch(restartBtnTextRect);
        var restartBtnTxt = restartBtnTextObj.AddComponent<Text>();
        restartBtnTxt.text = "重新挑战";
        restartBtnTxt.font = Resources.GetBuiltinResource<Font>("LegacyRuntime.ttf");
        restartBtnTxt.fontSize = 28;
        restartBtnTxt.fontStyle = FontStyle.Bold;
        restartBtnTxt.color = btnTextColor;
        restartBtnTxt.alignment = TextAnchor.MiddleCenter;
        restartBtnTxt.raycastTarget = false;

        // Next level button
        var nextBtnObj = CreateUIObject("下一关按钮", btnsObj.transform);
        var nextRect = nextBtnObj.GetComponent<RectTransform>();
        nextRect.anchorMin = new Vector2(0.54f, 0.15f);
        nextRect.anchorMax = new Vector2(0.92f, 0.85f);
        nextRect.sizeDelta = Vector2.zero;
        var nextBtnImg = nextBtnObj.AddComponent<Image>();
        nextBtnImg.color = btnGreenColor;
        nextBtnImg.raycastTarget = true;
        var nextBtn = nextBtnObj.AddComponent<Button>();
        nextBtn.targetGraphic = nextBtnImg;
        var nextBtnTextObj = CreateUIObject("Text", nextBtnObj.transform);
        var nextBtnTextRect = nextBtnTextObj.GetComponent<RectTransform>();
        SetFullStretch(nextBtnTextRect);
        var nextBtnTxt = nextBtnTextObj.AddComponent<Text>();
        nextBtnTxt.text = "下一关";
        nextBtnTxt.font = Resources.GetBuiltinResource<Font>("LegacyRuntime.ttf");
        nextBtnTxt.fontSize = 28;
        nextBtnTxt.fontStyle = FontStyle.Bold;
        nextBtnTxt.color = btnTextColor;
        nextBtnTxt.alignment = TextAnchor.MiddleCenter;
        nextBtnTxt.raycastTarget = false;

        // === ADD VictoryPanel COMPONENT ===
        var victoryPanelComp = rootObj.AddComponent<TowerDefense.UI.VictoryPanel>();

        // Use SerializedObject to wire the references
        var so = new SerializedObject(victoryPanelComp);

        so.FindProperty("_titleText").objectReferenceValue = titleText;

        var starsProp = so.FindProperty("_starImages");
        starsProp.arraySize = 3;
        for (int i = 0; i < 3; i++)
        {
            starsProp.GetArrayElementAtIndex(i).objectReferenceValue = starImages[i];
        }

        so.FindProperty("_killCountText").objectReferenceValue = statValueTexts[0];
        so.FindProperty("_goldText").objectReferenceValue = statValueTexts[1];
        so.FindProperty("_waveText").objectReferenceValue = statValueTexts[2];
        so.FindProperty("_restartButton").objectReferenceValue = restartBtn;
        so.FindProperty("_nextLevelButton").objectReferenceValue = nextBtn;

        so.ApplyModifiedProperties();

        // === WIRE GameUI._victoryPanel ===
        var gameUIObj = canvas.transform.Find("顶部标题栏/GameUI");
        if (gameUIObj != null)
        {
            var gameUIComp = gameUIObj.GetComponent<TowerDefense.UI.GameUI>();
            if (gameUIComp != null)
            {
                var gameUISo = new SerializedObject(gameUIComp);
                gameUISo.FindProperty("_victoryPanel").objectReferenceValue = rootObj;
                gameUISo.ApplyModifiedProperties();
                Debug.Log("GameUI._victoryPanel wired successfully!");
            }
            else
            {
                Debug.LogWarning("GameUI component not found on 顶部标题栏/GameUI");
            }
        }
        else
        {
            Debug.LogWarning("顶部标题栏/GameUI not found in Canvas hierarchy");
        }

        // Mark scene dirty
        EditorSceneManager.MarkSceneDirty(canvas.gameObject.scene);

        Debug.Log("Victory Panel built successfully!");
    }

    static GameObject CreateUIObject(string name, Transform parent)
    {
        var go = new GameObject(name);
        go.transform.SetParent(parent, false);
        go.layer = 5; // UI layer
        go.AddComponent<RectTransform>();
        return go;
    }

    static void SetFullStretch(RectTransform rt)
    {
        rt.anchorMin = Vector2.zero;
        rt.anchorMax = Vector2.one;
        rt.offsetMin = Vector2.zero;
        rt.offsetMax = Vector2.zero;
        rt.pivot = new Vector2(0.5f, 0.5f);
    }
}

