args.script:
var canvas = UnityEngine.Object.FindObjectOfType<UnityEngine.Canvas>();
var victoryRoot = canvas.transform.Find("胜利界面");
if (victoryRoot == null) { Debug.LogError("胜利界面 not found!"); return; }

var font = Resources.GetBuiltinResource<Font>("LegacyRuntime.ttf");

// Color palette
var panelBg = new Color(0.18f, 0.12f, 0.08f, 0.96f);
var overlayCol = new Color(0f, 0f, 0f, 0.65f);
var titleCol = new Color(1f, 0.85f, 0.1f);
var starGold = new Color(1f, 0.85f, 0f, 1f);
var labelCol = new Color(0.85f, 0.78f, 0.65f);
var dividerCol = new Color(1f, 0.85f, 0.1f, 0.3f);
var ribbonCol = new Color(0.12f, 0.55f, 0.22f, 0.9f);
var btnGreen = new Color(0.2f, 0.72f, 0.35f, 1f);
var btnOrange = new Color(0.92f, 0.55f, 0.12f, 1f);

// Helper: set RectTransform stretch
void Stretch(RectTransform rt) {
    rt.anchorMin = Vector2.zero; rt.anchorMax = Vector2.one;
    rt.offsetMin = Vector2.zero; rt.offsetMax = Vector2.zero;
    rt.pivot = new Vector2(0.5f, 0.5f);
}

// === ROOT: layer 5, RectTransform ===
victoryRoot.gameObject.layer = 5;
var rootRt = victoryRoot.GetComponent<RectTransform>();
if (rootRt == null) rootRt = victoryRoot.gameObject.AddComponent<RectTransform>();
Stretch(rootRt);

// === OVERLAY ===
var ov = victoryRoot.Find("遮罩");
ov.gameObject.layer = 5;
Stretch(ov.GetComponent<RectTransform>());
var ovImg = ov.gameObject.AddComponent<Image>();
ovImg.color = overlayCol; ovImg.raycastTarget = true;

// === PANEL BG ===
var pn = victoryRoot.Find("面板背景");
pn.gameObject.layer = 5;
var pr = pn.GetComponent<RectTransform>();
pr.anchorMin = pr.anchorMax = pr.pivot = new Vector2(0.5f, 0.5f);
pr.sizeDelta = new Vector2(600f, 720f);
var pnImg = pn.gameObject.AddComponent<Image>();
pnImg.color = panelBg; pnImg.raycastTarget = true;

// === RIBBON ===
var rb = pn.Find("装饰丝带");
rb.gameObject.layer = 5;
var rr = rb.GetComponent<RectTransform>();
rr.anchorMin = new Vector2(0f, 1f); rr.anchorMax = new Vector2(1f, 1f);
rr.pivot = new Vector2(0.5f, 1f); rr.sizeDelta = new Vector2(0f, 8f);
rb.gameObject.AddComponent<Image>().color = ribbonCol;

// === TITLE ===
var tt = pn.Find("胜利标题");
tt.gameObject.layer = 5;
var tr = tt.GetComponent<RectTransform>();
tr.anchorMin = new Vector2(0f, 1f); tr.anchorMax = new Vector2(1f, 1f);
tr.pivot = new Vector2(0.5f, 1f); tr.sizeDelta = new Vector2(0f, 100f);
tr.anchoredPosition = new Vector2(0f, -30f);
var titleTxt = tt.gameObject.AddComponent<Text>();
titleTxt.text = "胜 利 !"; titleTxt.font = font; titleTxt.fontSize = 56;
titleTxt.fontStyle = FontStyle.Bold; titleTxt.color = titleCol;
titleTxt.alignment = TextAnchor.MiddleCenter;

// === DIVIDER ===
var dv = pn.Find("分割线");
dv.gameObject.layer = 5;
var dr = dv.GetComponent<RectTransform>();
dr.anchorMin = new Vector2(0.1f, 1f); dr.anchorMax = new Vector2(0.9f, 1f);
dr.pivot = new Vector2(0.5f, 1f); dr.sizeDelta = new Vector2(0f, 3f);
dr.anchoredPosition = new Vector2(0f, -130f);
dv.gameObject.AddComponent<Image>().color = dividerCol;

// === STARS ===
var ss = pn.Find("星星区域");
ss.gameObject.layer = 5;
var sr = ss.GetComponent<RectTransform>();
sr.anchorMin = new Vector2(0f, 1f); sr.anchorMax = new Vector2(1f, 1f);
sr.pivot = new Vector2(0.5f, 1f); sr.sizeDelta = new Vector2(0f, 120f);
sr.anchoredPosition = new Vector2(0f, -145f);

float[] sx = { -80f, 0f, 80f };
Image[] starImgs = new Image[3];
for (int i = 0; i < 3; i++) {
    var s = ss.Find("Star" + (i+1));
    s.gameObject.layer = 5;
    var scr = s.GetComponent<RectTransform>();
    scr.anchorMin = scr.anchorMax = scr.pivot = new Vector2(0.5f, 0.5f);
    scr.sizeDelta = new Vector2(70f, 70f);
    scr.anchoredPosition = new Vector2(sx[i], 0f);
    starImgs[i] = s.gameObject.AddComponent<Image>();
    starImgs[i].color = starGold;
}

// === STATS ===
var st = pn.Find("统计区域");
st.gameObject.layer = 5;
var str = st.GetComponent<RectTransform>();
str.anchorMin = new Vector2(0f, 1f); str.anchorMax = new Vector2(1f, 1f);
str.pivot = new Vector2(0.5f, 1f); str.sizeDelta = new Vector2(0f, 200f);
str.anchoredPosition = new Vector2(0f, -275f);

string[] sLabels = { "击杀数", "剩余金币", "存活波次" };
float[] sy = { -20f, -75f, -130f };
Text[] valTxts = new Text[3];
for (int i = 0; i < 3; i++) {
    var row = st.Find("StatRow" + i);
    row.gameObject.layer = 5;
    var rowr = row.GetComponent<RectTransform>();
    rowr.anchorMin = new Vector2(0.1f, 1f); rowr.anchorMax = new Vector2(0.9f, 1f);
    rowr.pivot = new Vector2(0.5f, 1f); rowr.sizeDelta = new Vector2(0f, 45f);
    rowr.anchoredPosition = new Vector2(0f, sy[i]);
    var rowBg = row.gameObject.AddComponent<Image>();
    rowBg.color = new Color(1f, 1f, 1f, 0.06f); rowBg.raycastTarget = false;

    var lb = row.Find("Label");
    lb.gameObject.layer = 5;
    var lr = lb.GetComponent<RectTransform>();
    lr.anchorMin = new Vector2(0f, 0f); lr.anchorMax = new Vector2(0.45f, 1f);
    lr.offsetMin = new Vector2(20f, 0f); lr.offsetMax = Vector2.zero;
    var lt = lb.gameObject.AddComponent<Text>();
    lt.text = sLabels[i]; lt.font = font; lt.fontSize = 26;
    lt.color = labelCol; lt.alignment = TextAnchor.MiddleLeft;

    var vl = row.Find("Value");
    vl.gameObject.layer = 5;
    var vr = vl.GetComponent<RectTransform>();
    vr.anchorMin = new Vector2(0.55f, 0f); vr.anchorMax = new Vector2(1f, 1f);
    vr.offsetMin = Vector2.zero; vr.offsetMax = new Vector2(-20f, 0f);
    var vt = vl.gameObject.AddComponent<Text>();
    vt.text = "0"; vt.font = font; vt.fontSize = 28;
    vt.fontStyle = FontStyle.Bold; vt.color = Color.white;
    vt.alignment = TextAnchor.MiddleRight;
    valTxts[i] = vt;
}

// === BUTTONS ===
var bt = pn.Find("按钮区域");
bt.gameObject.layer = 5;
var br = bt.GetComponent<RectTransform>();
br.anchorMin = new Vector2(0f, 0f); br.anchorMax = new Vector2(1f, 0f);
br.pivot = new Vector2(0.5f, 0f); br.sizeDelta = new Vector2(0f, 120f);
br.anchoredPosition = new Vector2(0f, 40f);

// Restart button
var rbtn = bt.Find("重新挑战按钮");
rbtn.gameObject.layer = 5;
var rbr = rbtn.GetComponent<RectTransform>();
rbr.anchorMin = new Vector2(0.08f, 0.15f); rbr.anchorMax = new Vector2(0.46f, 0.85f);
rbr.sizeDelta = Vector2.zero;
var rbi = rbtn.gameObject.AddComponent<Image>(); rbi.color = btnOrange;
var rb2 = rbtn.gameObject.AddComponent<Button>(); rb2.targetGraphic = rbi;
var rbt = rbtn.Find("Text");
rbt.gameObject.layer = 5;
Stretch(rbt.GetComponent<RectTransform>());
var rbtxt = rbt.gameObject.AddComponent<Text>();
rbtxt.text = "重新挑战"; rbtxt.font = font; rbtxt.fontSize = 28;
rbtxt.fontStyle = FontStyle.Bold; rbtxt.color = Color.white;
rbtxt.alignment = TextAnchor.MiddleCenter;

// Next level button
var nbtn = bt.Find("下一关按钮");
nbtn.gameObject.layer = 5;
var nbr = nbtn.GetComponent<RectTransform>();
nbr.anchorMin = new Vector2(0.54f, 0.15f); nbr.anchorMax = new Vector2(0.92f, 0.85f);
nbr.sizeDelta = Vector2.zero;
var nbi = nbtn.gameObject.AddComponent<Image>(); nbi.color = btnGreen;
var nb2 = nbtn.gameObject.AddComponent<Button>(); nb2.targetGraphic = nbi;
var nbt = nbtn.Find("Text");
nbt.gameObject.layer = 5;
Stretch(nbt.GetComponent<RectTransform>());
var nbtxt = nbt.gameObject.AddComponent<Text>();
nbtxt.text = "下一关"; nbtxt.font = font; nbtxt.fontSize = 28;
nbtxt.fontStyle = FontStyle.Bold; nbtxt.color = Color.white;
nbtxt.alignment = TextAnchor.MiddleCenter;

// === ADD VictoryPanel COMPONENT ===
var vpComp = victoryRoot.gameObject.AddComponent<TowerDefense.UI.VictoryPanel>();
var so = new UnityEditor.SerializedObject(vpComp);
so.FindProperty("_titleText").objectReferenceValue = titleTxt;
var sp = so.FindProperty("_starImages");
sp.arraySize = 3;
for (int i = 0; i < 3; i++) sp.GetArrayElementAtIndex(i).objectReferenceValue = starImgs[i];
so.FindProperty("_killCountText").objectReferenceValue = valTxts[0];
so.FindProperty("_goldText").objectReferenceValue = valTxts[1];
so.FindProperty("_waveText").objectReferenceValue = valTxts[2];
so.FindProperty("_restartButton").objectReferenceValue = rb2;
so.FindProperty("_nextLevelButton").objectReferenceValue = nb2;
so.ApplyModifiedProperties();

// === WIRE GameUI._victoryPanel ===
var gui = canvas.transform.Find("顶部标题栏/GameUI");
if (gui != null) {
    var gc = gui.GetComponent<TowerDefense.UI.GameUI>();
    if (gc != null) {
        var gso = new UnityEditor.SerializedObject(gc);
        gso.FindProperty("_victoryPanel").objectReferenceValue = victoryRoot.gameObject;
        gso.ApplyModifiedProperties();
        Debug.Log("GameUI._victoryPanel wired!");
    }
}

UnityEditor.EditorSceneManager.MarkSceneDirty(canvas.gameObject.scene);
Debug.Log("Victory Panel fully configured!");

